async function requestWithTimeout<T>(url: string, timeoutMs = 5000): Promise<T> {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const response = await fetch(url, { signal: controller.signal });
    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);
    return await response.json();
  } finally {
    clearTimeout(timeoutId);
  }
}

/**
 * 获取仪表盘数据
 * 采用 Promise.all 结合 错误捕获 机制实现优雅降级
 */
async function fetchDashboardData(): Promise<DashboardData> {
  try {
    // 为每个请求包裹一个 catch 块，确保单个接口失败不影响整体 Promise.all
    const [user, orders, metrics] = await Promise.all([
      requestWithTimeout<User>('/api/user').catch((err) => {
        console.error('Failed to fetch user data:', err);
        return null;
      }),
      requestWithTimeout<Order[]>('/api/orders').catch((err) => {
        console.error('Failed to fetch orders data:', err);
        return null;
      }),
      requestWithTimeout<Metrics>('/api/metrics').catch((err) => {
